var express = require('express');
var app = express();
app.use('/', express.static(__dirname + '/public'));
app.use('/animdb.json', (req, res) => {
    const animdb = require('../animdb.json');
    res.write(JSON.stringify(animdb));
    res.end();
});
app.listen(3000, function() { console.log('Go to http://localhost:3000 to see the AnimDB Viewer...'); });
